async def main(args: Args) -> Output:
    _p = getattr(args, "params", None) or {}
    raw = str(_p.get("prompt_in") or "").strip()
    max_len = 640
    if len(raw) <= max_len:
        out = raw
    else:
        cut = raw[:max_len]
        out = cut
        for sep in ("。", "，", ",", ";", "；", "\n", "、"):
            i = cut.rfind(sep)
            if i > int(max_len * 0.55):
                out = cut[: i + 1].strip()
                break
    if len(out) > max_len:
        out = out[:max_len].strip()
    return {"prompt_out": out}

